.dropdown {
  --animation: slideDown;
  --animation-time: 0.3s;
  --menu-gap: 12px;
  width: min(520px, calc(100vw - 32px));
  position: relative;
  display: grid;
  place-content: center;
  margin: 16px auto 90px auto;
}

.dropdown .dropdown-btn {
  appearance: none;
  width: 240px;
  display: inline-flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;

  border: 1px solid color-mix(in srgb, var(--text, #111) 14%, transparent);
  border-radius: 14px;
  padding: 12px 14px;

  background: linear-gradient(135deg, color-mix(in srgb, #ffffff 14%, transparent), rgba(255, 255, 255, 0.02));
  color: var(--text, #111);
  cursor: pointer;

  font-weight: 700;
  letter-spacing: -0.01em;

  box-shadow: 0 18px 45px rgba(0, 0, 0, 0.25);
  transition:
    transform 120ms ease,
    box-shadow 200ms ease,
    background 180ms ease,
    border-color 180ms ease;
}

.dropdown .dropdown-btn:hover {
  box-shadow: 0 24px 60px rgba(0, 0, 0, 0.35);
}

.dropdown .dropdown-btn:active {
  transform: translateY(1px);
}

.dropdown .dropdown-btn:focus-visible {
  outline: 3px solid color-mix(in srgb, #3b82f6 55%, transparent);
  outline-offset: 3px;
}

.dropdown .arrow {
  display: inline-block;
  font-size: 14px;
  opacity: 0.85;
  transition: transform 200ms ease;
}

.dropdown .dropdown-container {
  width: min(360px, 100%);
  position: absolute;
  top: calc(100% + var(--menu-gap));
  left: 50%;
  transform: translateX(-50%);
  z-index: 10;

  opacity: 0;
  visibility: hidden;
  pointer-events: none;

  border-radius: 16px;
  border: 1px solid color-mix(in srgb, var(--text, #111) 14%, transparent);
  background: color-mix(in srgb, var(--surface, #0b0c10) 85%, transparent);
  box-shadow: 0 22px 70px rgba(0, 0, 0, 0.45);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);

  overflow: hidden;
  interpolate-size: allow-keywords;
}

.dropdown .dropdown-container::before {
  content: "";
  position: absolute;
  inset: calc(var(--menu-gap) * -1) 0 auto 0;
  height: var(--menu-gap);
}

.dropdown .dropdown-list {
  list-style: none;
  padding: 6px;
  margin: 0;
}

.dropdown .dropdown-list li {
  border-radius: 12px;
}

.dropdown .dropdown-list a {
  display: block;
  padding: 10px 12px;
  text-decoration: none;
  color: color-mix(in srgb, var(--text, #111) 92%, var(--muted, #9aa3b5));
  font-weight: 650;
  letter-spacing: -0.01em;
  transition: background 160ms ease, color 160ms ease;
}

.dropdown .dropdown-list a:hover {
  background: color-mix(in srgb, var(--primary, #7c5dff) 16%, transparent);
  color: var(--text, #111);
}

.dropdown .dropdown-list a:focus-visible {
  outline: 3px solid color-mix(in srgb, #3b82f6 55%, transparent);
  outline-offset: 2px;
}

.dropdown .dropdown-btn:hover + .dropdown-container,
.dropdown .dropdown-btn:focus + .dropdown-container,
.dropdown .dropdown-container:hover {
  visibility: visible;
  opacity: 1;
  pointer-events: all;
  animation: var(--animation) var(--animation-time) ease forwards;
}

.dropdown .dropdown-btn:hover .arrow,
.dropdown .dropdown-btn:focus .arrow,
.dropdown .dropdown-container:hover ~ .dropdown-btn .arrow {
  transform: rotate(180deg);
}

