#popup {
  --animation: slideDown;

  --animation-time: 0.3s;
 color: white;
  margin: auto auto;
  width: min(520px, calc(100vw - 32px));
  padding: 22px 22px 18px;
  border: 1px solid color-mix(in srgb, var(--text) 14%, transparent);
  border-radius: 14px;
  background: color-mix(in srgb, var(--bg) 92%, #ffffff 8%);
  color: var(--text);
  box-shadow: 0 18px 60px rgba(0, 0, 0, 0.35);

  text-align: left;

  h4 {
    margin: 0;
    font-size: 18px;
    font-weight: 700;
    line-height: 1.25;
  }

  button {
    appearance: none;
    border: 1px solid color-mix(in srgb, var(--text) 14%, transparent);
    background: transparent;
    color: inherit;
    border-radius: 10px;
    padding: 10px 14px;
    font-weight: 600;
    cursor: pointer;
    transition:
      background 160ms ease,
      border-color 160ms ease,
      transform 120ms ease;
  }

  button:hover {
    background: color-mix(in srgb, var(--text) 6%, transparent);
  }

  button:active {
    transform: translateY(1px);
  }

  button:focus-visible {
    outline: 3px solid color-mix(in srgb, #3b82f6 55%, transparent);
    outline-offset: 2px;
  }

  #delete {
    border-color: color-mix(in srgb, #ef4444 55%, transparent) !important;
    background: color-mix(in srgb, #ef4444 12%, transparent) !important;
  }

  #delete:hover {
    background: color-mix(in srgb, #ef4444 18%, transparent) !important;
    border-color: color-mix(in srgb, #ef4444 70%, transparent) !important;
  }

  #delete:focus-visible {
    outline: 3px solid color-mix(in srgb, #ef4444 55%, transparent) !important;
  }

  &:popover-open {
    display: grid;
    grid-template-columns: 1fr;
    gap: 14px;
    animation: var(--animation) var(--animation-time) ease forwards;
  }
  &::backdrop {
    background: rgba(0, 0, 0, 0.55);
    backdrop-filter: blur(6px);
  }
}
